import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import GlowButton from '../components/GlowButton';
import PageLayout from '../components/PageLayout';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!email.trim() || !password) {
      setError('Please provide your email and password.');
      return;
    }

    // TODO: call backend auth API
    // For now just pretend success and navigate home
    navigate('/');
  };

  return (
    <PageLayout className="min-h-screen" contentClassName="flex min-h-[calc(100vh-12rem)] items-center justify-center">
      <section className="flex w-full justify-center">
        <div className="glass-card w-full max-w-md rounded-[2rem] bg-gradient-to-br from-[#3D4A2F]/70 via-[#2B2B2B]/92 to-[#2B2B2B]/95 p-8 text-[#F1E7C8] sm:p-10">
      <p className="section-eyebrow mb-3 text-center text-white/40">Welcome Back</p>
      <h2 className="section-title mb-8 text-center text-gold serif-glow">Sign In</h2>
      <form onSubmit={handleSubmit} className="space-y-5">
        <label className="block">
          <span className="text-[11px] font-black uppercase tracking-[0.24em] text-white/58">Email</span>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="premium-input mt-2"
            placeholder="you@example.com"
            required
          />
        </label>

        <label className="block">
          <span className="text-[11px] font-black uppercase tracking-[0.24em] text-white/58">Password</span>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="premium-input mt-2"
            placeholder="Your password"
            required
          />
        </label>

        {error && <div className="rounded-2xl border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm text-red-300">{error}</div>}

        <GlowButton
          type="submit"
          className="w-full justify-center border-gold/45 bg-panel/90 py-4 text-center"
        >
          Sign In
        </GlowButton>
      </form>

      <div className="mt-8 text-center text-white/65">
        <p className="text-sm">Don't have an account?</p>
        <Link to="/register" className="font-medium text-gold transition-colors hover:text-[#F1E7C8]">
          Create an account
        </Link>
        <div className="mt-2">
          <Link to="/forgot-password" className="text-sm text-emerald transition-colors hover:text-[#F1E7C8]">
            Forgot password?
          </Link>
        </div>
      </div>
        </div>
      </section>
    </PageLayout>
  );
};

export default Login;
